import{_ as t,o as r,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"薛定谔的猫","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/薛定谔的猫.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/薛定谔的猫.md"}'),d={name:"4.资源分区/1.血统与训练/6.一次性血统/薛定谔的猫.md"};function p(_,a,l,i,c,h){return r(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"薛定谔的猫",tabindex:"-1"},[s("薛定谔的猫 "),e("a",{class:"header-anchor",href:"#薛定谔的猫","aria-label":'Permalink to "薛定谔的猫"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序009")])])],-1),o('<h1 id="薛定谔的猫-1" tabindex="-1">薛定谔的猫 <a class="header-anchor" href="#薛定谔的猫-1" aria-label="Permalink to &quot;薛定谔的猫&quot;">​</a></h1><p>薛定谔的猫 S+9600<br> 薛定谔的猫是一个经典的思想实验，该实验试图从宏观尺度阐述微观尺度的量子叠加原理的问题，巧妙地把微观物质在观测后是粒子还是波的存在形式和宏观的猫联系起来。而将这个实验中的概念提取并改造成一种概念能力，变成一种概念级血统。</p><p>隔绝干涉的封闭盒子：由实验中盒子概念改造而成的能力，作为实验中将猫与外部观察测者隔离的盒子这个概念，其衍生的能力使血统拥有者可以随时进入或离开一个与外界隔离的封闭空间，该空间的容量无限并且无法被外界事物的任何方式观测与影响，而处于该空间内的事物也无法以任何方式观测与影响外界，而血统拥有者也可以把持有归属权的物品也带入该空间内，需要注意的是每次进入和离开该空间必须间隔12秒，否则该空间会失去封闭性并且崩溃，其中的一切事物也会出现在外界。这视为一个S级异空间效果并具有SS级免疫空间来源的隔绝效果。</p><p>猫的生死叠加态：由中盒子未打开时猫的状态概念改造而成的能力，作为实验中猫处于既死又活的叠加态这个概念，其衍生的能力使血统拥有者在承受致命危险后，自动进入封闭空间，并于12秒后自动出现于外界，此时血统拥有者有一半概率是处于承受致命危险后的死亡状态，有一半概率是处于完全恢复的存活状态。这视为SSS级复活能力。</p><p>猫的生或死：由中盒子打开后猫的状态概念改造而成的能力，作为实验中猫从既死又活的叠加态坍缩成活着或死亡中一种状态的这个概念，其衍生的能力使血统拥有者所经历和将要经历的一切，从无数的可能性坍缩成唯一的现实，这会使一切干扰或者影响血统拥有者的命运与未来的能力无法生效，这视为一种SSS级命运来源免疫。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const b=t(d,[["render",p]]);export{f as __pageData,b as default};
